/**
 * Model StackKitTool
 * Junction table linking StackKits to Tools with metadata
 */
export type StackKitTool = $Result.DefaultSelection<Prisma.$StackKitToolPayload>
/**
 * Model ValidationRule
 * Validation rules that are exported to CUE schemas
 */
export type ValidationRule = $Result.DefaultSelection<Prisma.$ValidationRulePayload>
/**
 * Model Setting
 * Classification of all settings as perma or flexible
 */
export type Setting = $Result.DefaultSelection<Prisma.$SettingPayload>
/**
 * Model Pattern
 * Reusable patterns for StackKit development
 */
export type Pattern = $Result.DefaultSelection<Prisma.$PatternPayload>
/**
 * Model Decision
 * Architecture Decision Records stored in database
 */
export type Decision = $Result.DefaultSelection<Prisma.$DecisionPayload>
/**
 * Model AuditLog
 * Audit trail for all changes
 */
export type AuditLog = $Result.DefaultSelection<Prisma.$AuditLogPayload>
/**
 * Model ToolVersion
 * Tool version tracking — detect updates, breaking changes, security patches
 */
export type ToolVersion = $Result.DefaultSelection<Prisma.$ToolVersionPayload>
/**
 * Model ToolEvaluation
 * Structured tool evaluation — analogous to Websearch-UI's crawl quality assessment
 */
export type ToolEvaluation = $Result.DefaultSelection<Prisma.$ToolEvaluationPayload>
/**
 * Model CrawlSource
 * Scheduled discovery sources — enables automated continuous tool discovery
 */
export type CrawlSource = $Result.DefaultSelection<Prisma.$CrawlSourcePayload>
/**
 * Model DiscoveryJob
 * Discovery jobs — track automated tool discovery runs (like Websearch-UI crawl jobs)
 */
